css:
color-scheme: dark;
  --app-bg: #07060c;
  --app-surface: rgba(255, 255, 255, 0.028);
  --app-surface-hover: rgba(255, 255, 255, 0.045);
  --app-border: rgba(255, 255, 255, 0.065);
  --app-border-strong: rgba(255, 255, 255, 0.11);
  --app-text: #f0edf5;
  --app-text-muted: #8d8798;
  --app-accent: #c8a8ff;
  --app-accent-soft: rgba(200, 168, 255, 0.14);
  --app-accent-border: rgba(200, 168, 255, 0.3);
  --app-accent-nav: rgba(200, 168, 255, 0.1);
  --app-elevated: #0d0b13;
  --app-glow-1: rgba(170, 120, 255, 0.13);
  --app-glow-2: rgba(230, 130, 190, 0.09);
  --app-card-shadow: 0 20px 40px rgba(0, 0, 0, 0.52), inset 0 1px 0 rgba(255, 255, 255, 0.09), inset 0 -1px 0 rgba(0, 0, 0, 0.42);
  --app-sidebar-bg: radial-gradient(circle at 14% -3%, var(--app-glow-1), transparent 42%), radial-gradient(circle at 90% 106%, var(--app-glow-2), transparent 40%), var(--app-bg);
  --app-shell-bg: var(--app-sidebar-bg);
  --media-snake-1: rgba(140, 100, 220, 0.14);
  --media-snake-2: rgba(190, 150, 255, 0.58);
  --media-snake-3: rgba(230, 210, 255, 0.96);
  --media-snake-4: rgba(220, 140, 200, 0.72);
  --bg-primary: var(--app-bg);
  --bg-secondary: var(--app-elevated);
  --bg-elevated: #12101a;
  --bg-glass: rgba(12, 10, 18, 0.86);
  --text-primary: var(--app-text);
  --text-secondary: var(--app-text-muted);
  --text-tertiary: rgba(141, 135, 152, 0.72);
  --accent: var(--app-accent);
  --accent-blue: var(--app-accent);
  --focus-glow: rgba(200, 168, 255, 0.22);
